# pyre-strict
"""Paired-tile ping-pong lowering for FA-forward-shaped schedules.

Feasibility-to-feature bridge (perf-dir-6 direction 1): instead of one CTA per
M-tile, each CTA takes TWO adjacent M-tiles; the softmax warp group is emitted
with TLX's `replicate=2` (one 4-warp replica per tile), a single 1-warp MMA
task issues both replicas' QK and PV MMAs (in-order completion on the shared
TC lets K/V ring releases ride the second dot only), the acc correction runs
in the default WG (tutorial-style), and the K/V TMA loads + SMEM ring are
shared between replicas. The choreography mirrors
third_party/tlx/tutorials/blackwell_fa_ws.py (the proven +25% structure on
B200), with case3's BN=64 geometry and SMEM alpha/l/m channels instead of the
tutorial's TMEM-reuse staging (which requires 128-row slices).

Scope guard: this is a template lowering specialized to the case3-v2 FA fwd
pattern. `validate()` checks the schedule graph matches (kernel signature,
warp-group roles, buffer inventory) and refuses anything else, so `--pingpong`
cannot silently mis-lower other kernels. Generalizing this into the regular
emitter path is follow-up work.

Deltas vs the baseline emission it replaces (why they exist):
  * K ring depth 1 -> 2: with one tile in flight the two replicas lockstep on
    K reuse; depth 2 lets replica 1 run one K-tile behind replica 0.
  * The baseline's dead buffers (unused (128,64) staging pair, 48 KB) are not
    emitted -- the doubled Q/c tiles would not fit the SMEM budget otherwise.
  * A `RECOMMENDED_GRID_DIVISOR = 2` module constant is emitted (mirrors the
    launch-hints RECOMMENDED_* pattern); launchers divide grid dim 0 by it.
    Odd tile counts: replica 1 of the last CTA clamps its tile index for loads
    and skips its output store.
"""

from __future__ import annotations

from .schedule_graph import ScheduleGraph


class PingpongNotApplicable(Exception):
    pass


def _fail(msg: str) -> None:
    raise PingpongNotApplicable(f"--pingpong: schedule graph does not match "
                                f"the FA paired-tile pattern: {msg}")


def validate(g: ScheduleGraph) -> dict:
    """Check the graph is the case3-v2 FA fwd shape; return template params."""
    if len(g.loops) != 1:
        _fail(f"expected exactly 1 scheduled loop, got {len(g.loops)}")
    loop = g.loops[0]
    sl = loop.schedule
    if len(loop.warp_groups) < 5:
        _fail(f"expected >= 5 warp groups, got {len(loop.warp_groups)}")

    # Two TC MMA nodes (QK and PV) in distinct warp groups, and an SFU-bearing
    # softmax group.
    mma_wgs = {n.warp_group for n in sl.nodes if n.op_kind == "ttng.tc_gen5_mma"}
    if len(mma_wgs) != 2:
        _fail(f"expected 2 tc_gen5_mma warp groups, got {sorted(mma_wgs)}")
    sfu_wgs = [wg.id for wg in loop.warp_groups if "SFU" in wg.pipelines]
    if len(sfu_wgs) != 1:
        _fail(f"expected exactly 1 SFU (softmax) warp group, got {sfu_wgs}")

    # Buffer inventory: K/V rings (BN, D) + a TMEM accumulator family.
    smem_kv = [b for b in sl.buffers if b.kind == "smem" and len(b.shape) == 2
               and b.shape[0] < b.shape[1]]
    if not smem_kv:
        _fail("no (BN, D) SMEM K/V buffers found")
    bn, d = smem_kv[0].shape
    if any(tuple(b.shape) != (bn, d) for b in smem_kv):
        _fail(f"inconsistent K/V tile shapes: {[b.shape for b in smem_kv]}")
    v_depth = max(b.count for b in smem_kv)

    args = [a.name for a in g.kernel.args]
    if len(args) != 8:
        _fail(f"expected the 8-arg FA fwd signature, got {args}")

    kname = g.kernel.name
    bm = 2 * bn  # case3: BM=128, BN=64
    if d != 128 or bm != 128:
        _fail(f"unexpected geometry BM={bm} BN={bn} D={d} (template assumes "
              f"BM=128, D=128)")

    return {
        "kname": kname,
        "args": args,
        "BM": bm,
        "BN": bn,
        "D": d,
        "V_DEPTH": v_depth,
        "K_DEPTH": 2,
    }


def emit_pingpong(g: ScheduleGraph) -> str:
    p = validate(g)
    kname = p["kname"]
    q_a, k_a, v_a, out_a, mlse_a, scale_a, h_a, nctx_a = p["args"]
    bm, bn, d = p["BM"], p["BN"], p["D"]
    kd, vd = p["K_DEPTH"], p["V_DEPTH"]
    kv_bytes = bn * d * 2  # bf16
    q_bytes = bm * d * 2

    return f'''# @generated by sched2tlx --pingpong — do not edit by hand.
# Source: schedule_graph for kernel `{kname}` (paired-tile ping-pong lowering)
# Structure: default=correction+epilogue, 1 loader task (Q x2 + K + V),
#            1 MMA task (both replicas' QK+PV dots), softmax replicate=2.
import torch
import triton
import triton.language as tl
import triton.language.extra.tlx as tlx

RECOMMENDED_GRID_DIVISOR = 2

@triton.jit
def {kname}(
    {q_a},
    {k_a},
    {v_a},
    {out_a},
    {mlse_a},
    {scale_a},
    {h_a},
    {nctx_a}
):
    # ── Preamble ──
    pid_0 = tl.program_id(0)
    pid_1 = tl.program_id(1)
    off_z = (pid_1 * {nctx_a})
    n_tiles = ({nctx_a} + {bm - 1}) // {bm}
    tile_1 = (pid_0 * 2 + 1)
    row_0 = (off_z + (pid_0 * 2) * {bm})
    row_1 = (off_z + tl.minimum(tile_1, n_tiles - 1) * {bm})
    trips = ({nctx_a} // {bn})
    hn = ({h_a} * {nctx_a})
    q_desc = tl.make_tensor_descriptor({q_a}, [hn, {d}], [{d}, 1], [{bm}, {d}])
    k_desc = tl.make_tensor_descriptor({k_a}, [hn, {d}], [{d}, 1], [{bn}, {d}])
    v_desc = tl.make_tensor_descriptor({v_a}, [hn, {d}], [{d}, 1], [{bn}, {d}])
    out_desc = tl.make_tensor_descriptor({out_a}, [hn, {d}], [{d}, 1], [{bm}, {d}])

    # ── SMEM (K/V rings shared; Q/c/alpha/epi channels per replica) ──
    v_ring = tlx.local_alloc(({bn}, {d}), tl.bfloat16, {vd})
    k_ring = tlx.local_alloc(({bn}, {d}), tl.bfloat16, {kd})
    q_tiles = tlx.local_alloc(({bm}, {d}), tl.bfloat16, 2)
    c_tiles = tlx.local_alloc(({bm}, {d}), tl.bfloat16, 2)
    alpha_ch = tlx.local_alloc(({bm},), tl.float32, 2)
    epi_m_ch = tlx.local_alloc(({bm},), tl.float32, 2)
    epi_l_ch = tlx.local_alloc(({bm},), tl.float32, 2)

    # ── TMEM (per replica: S, P bridge, accumulator) ──
    s_tmem = tlx.local_alloc(({bm}, {bn}), tl.float32, 2, tlx.storage_kind.tmem)
    p_tmem = tlx.local_alloc(({bm}, {bn}), tl.bfloat16, 2, tlx.storage_kind.tmem)
    acc_tmem = tlx.local_alloc(({bm}, {d}), tl.float32, 2, tlx.storage_kind.tmem)

    # ── Mbarriers ──
    q_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    k_full = tlx.alloc_barriers(num_barriers={kd}, arrive_count=1)
    k_empty = tlx.alloc_barriers(num_barriers={kd}, arrive_count=1)
    v_full = tlx.alloc_barriers(num_barriers={vd}, arrive_count=1)
    v_empty = tlx.alloc_barriers(num_barriers={vd}, arrive_count=1)
    qk_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    s_free = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    alpha_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    alpha_empty = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    p_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    p_empty = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    acc_scaled = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    pv_done = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    acc_done = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    epi_m_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)
    epi_l_full = tlx.alloc_barriers(num_barriers=2, arrive_count=1)

    with tlx.async_tasks():
        # ── correction + epilogue (default) ──
        with tlx.async_task("default"):
            for it in range(0, trips, 1):
                ph = it & 1
                tlx.barrier_wait(alpha_full[0], ph)
                a0 = tlx.local_load(alpha_ch[0])
                tlx.barrier_arrive(alpha_empty[0], 1)
                tlx.barrier_wait(pv_done[0], ph)
                acc0 = tlx.local_load(acc_tmem[0])
                tlx.local_store(acc_tmem[0], acc0 * a0[:, None])
                tlx.barrier_arrive(acc_scaled[0], 1)
                tlx.barrier_wait(alpha_full[1], ph)
                a1 = tlx.local_load(alpha_ch[1])
                tlx.barrier_arrive(alpha_empty[1], 1)
                tlx.barrier_wait(pv_done[1], ph)
                acc1 = tlx.local_load(acc_tmem[1])
                tlx.local_store(acc_tmem[1], acc1 * a1[:, None])
                tlx.barrier_arrive(acc_scaled[1], 1)
            # epilogue, replica 0 then 1
            tlx.barrier_wait(epi_m_full[0], 0)
            m_0 = tlx.local_load(epi_m_ch[0])
            tlx.barrier_wait(epi_l_full[0], 0)
            l_0 = tlx.local_load(epi_l_ch[0])
            tlx.barrier_wait(acc_done[0], 0)
            out_0 = (tlx.local_load(acc_tmem[0]) / l_0[:, None]).to(tl.bfloat16)
            tlx.local_store(c_tiles[0], out_0)
            tlx.fence_async_shared()
            tlx.async_descriptor_store(out_desc, c_tiles[0], [row_0, 0])
            tlx.barrier_wait(epi_m_full[1], 0)
            m_1 = tlx.local_load(epi_m_ch[1])
            tlx.barrier_wait(epi_l_full[1], 0)
            l_1 = tlx.local_load(epi_l_ch[1])
            tlx.barrier_wait(acc_done[1], 0)
            out_1 = (tlx.local_load(acc_tmem[1]) / l_1[:, None]).to(tl.bfloat16)
            tlx.local_store(c_tiles[1], out_1)
            tlx.fence_async_shared()
            if tile_1 < n_tiles:
                tlx.async_descriptor_store(out_desc, c_tiles[1], [row_1, 0])
            tlx.async_descriptor_store_wait(0)

        # ── loader: Q x2 (per-tile resident), then shared K/V rings ──
        with tlx.async_task(num_warps=1, num_regs=24):
            tlx.barrier_expect_bytes(q_full[0], {q_bytes})
            tlx.async_descriptor_load(q_desc, q_tiles[0], [row_0, 0], q_full[0])
            tlx.barrier_expect_bytes(q_full[1], {q_bytes})
            tlx.async_descriptor_load(q_desc, q_tiles[1], [row_1, 0], q_full[1])
            for it in range(0, trips, 1):
                kb = it % {kd}
                tlx.barrier_wait(k_empty[kb], ((it // {kd}) & 1) ^ 1)
                tlx.barrier_expect_bytes(k_full[kb], {kv_bytes})
                tlx.async_descriptor_load(k_desc, k_ring[kb], [(off_z + it * {bn}), 0], k_full[kb])
                vb = it % {vd}
                tlx.barrier_wait(v_empty[vb], ((it // {vd}) & 1) ^ 1)
                tlx.barrier_expect_bytes(v_full[vb], {kv_bytes})
                tlx.async_descriptor_load(v_desc, v_ring[vb], [(off_z + it * {bn}), 0], v_full[vb])

        # ── MMA issuer: both replicas' QK + PV dots (in-order on the TC) ──
        with tlx.async_task(num_warps=1, num_regs=24):
            tlx.barrier_wait(q_full[0], 0)
            tlx.barrier_wait(q_full[1], 0)
            tlx.barrier_arrive(s_free[0], 1)
            tlx.barrier_arrive(s_free[1], 1)
            tlx.barrier_arrive(pv_done[0], 1)
            tlx.barrier_arrive(pv_done[1], 1)
            for it in range(0, trips, 1):
                ph = it & 1
                kb = it % {kd}
                tlx.barrier_wait(k_full[kb], (it // {kd}) & 1)
                k_t = tlx.local_trans(k_ring[kb])
                tlx.barrier_wait(s_free[0], ph)
                tlx.async_dot(q_tiles[0], k_t, s_tmem[0], use_acc=False, mBarriers=[qk_full[0]])
                tlx.barrier_wait(s_free[1], ph)
                tlx.async_dot(q_tiles[1], k_t, s_tmem[1], use_acc=False, mBarriers=[qk_full[1], k_empty[kb]])
                vb = it % {vd}
                tlx.barrier_wait(v_full[vb], (it // {vd}) & 1)
                tlx.barrier_wait(p_full[0], ph)
                tlx.barrier_wait(acc_scaled[0], ph)
                use_acc = (it > 0)
                tlx.async_dot(p_tmem[0], v_ring[vb], acc_tmem[0], use_acc=use_acc, mBarriers=[p_empty[0], pv_done[0]])
                tlx.barrier_wait(p_full[1], ph)
                tlx.barrier_wait(acc_scaled[1], ph)
                tlx.async_dot(p_tmem[1], v_ring[vb], acc_tmem[1], use_acc=use_acc, mBarriers=[p_empty[1], pv_done[1], v_empty[vb]])
            tlx.tcgen05_commit(acc_done[0])
            tlx.tcgen05_commit(acc_done[1])

        # ── softmax, one replica per tile ──
        with tlx.async_task(num_warps=4, num_regs=152, replicate=2):
            cid = tlx.async_task_replica_id()
            m_i = tl.full(({bm},), float('-inf'), tl.float32)
            l_i = tl.full(({bm},), 1, tl.float32)
            for it in range(0, trips, 1):
                ph = it & 1
                tlx.barrier_wait(qk_full[cid], ph)
                s = tlx.local_load(s_tmem[cid])
                tlx.barrier_arrive(s_free[cid], 1)
                m_ij = tl.maximum(m_i, tl.max(s, 1) * ({scale_a} * 1.4426950408889634))
                alpha = tl.math.exp2(m_i - m_ij)
                p = tl.math.exp2(s * ({scale_a} * 1.4426950408889634) - m_ij[:, None])
                tlx.barrier_wait(alpha_empty[cid], ph ^ 1)
                tlx.local_store(alpha_ch[cid], alpha)
                tlx.barrier_arrive(alpha_full[cid], 1)
                tlx.barrier_wait(p_empty[cid], ph ^ 1)
                tlx.local_store(p_tmem[cid], p.to(tl.bfloat16))
                tlx.barrier_arrive(p_full[cid], 1)
                l_i = l_i * alpha + tl.sum(p, 1)
                m_i = m_ij
            tlx.local_store(epi_m_ch[cid], m_i)
            tlx.barrier_arrive(epi_m_full[cid], 1)
            tlx.local_store(epi_l_ch[cid], l_i)
            tlx.barrier_arrive(epi_l_full[cid], 1)
'''
